command:
const tokens = canvas.tokens.controlled.filter(t => t.actor);
if (!tokens.length) return ui.notifications.warn("Sélectionne d'abord des tokens.");
const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: `Dégâts / Stress — ${tokens.length} token(s)` },
  content: `
    <div class="form-group"><label>Type</label>
      <select name="mode"><option value="wounds">Blessures</option><option value="strain">Stress</option>
      <option value="healW">Soin (blessures)</option><option value="healS">Récup (stress)</option></select></div>
    <div class="form-group"><label>Montant</label><input type="number" name="amount" value="5" min="1"/></div>
    <div class="form-group"><label><input type="checkbox" name="soak" checked/> Retirer l'encaissement (blessures seulement)</label></div>`,
  buttons: [{ action: "ok", label: "Appliquer", default: true,
    callback: (event, button) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(button.form).object }],
});
if (!fd) return;
const amount = Number(fd.amount);
const lines = [];
for (const t of tokens) {
  const a = t.actor, st = a.system?.stats ?? {};
  const soak = fd.soak && fd.mode === "wounds" ? Number(st.soak?.value ?? 0) : 0;
  const heal = fd.mode.startsWith("heal");
  const key = (fd.mode === "wounds" || fd.mode === "healW") ? "wounds" : "strain";
  const cur = Number(st[key]?.value ?? 0);
  const delta = heal ? -amount : Math.max(0, amount - soak);
  const next = Math.max(0, cur + delta);
  await a.update({ [`system.stats.${key}.value`]: next });
  const max = Number(st[key]?.max ?? 0);
  lines.push(`${t.name} : ${key === "wounds" ? "blessures" : "stress"} ${cur} → ${next}${max ? `/${max}` : ""}${soak ? ` (encaissement ${soak})` : ""}${max && next >= max ? " ⚠️ <strong>seuil dépassé !</strong>" : ""}`);
}
await ChatMessage.create({ content: `<h4>🩹 ${fd.mode.startsWith("heal") ? "Soins" : "Dégâts"}</h4><p>${lines.join("<br>")}</p>`,
  whisper: ChatMessage.getWhisperRecipients("GM").map(u => u.id) });
